bool isMajority(std::vector<int> a, int n) {
    std::unordered_map<int, int> mp;
    for (int i = 0; i < n; i++) {
        if (mp.find(a[i]) != mp.end()) {
            mp[a[i]]++;
        } else {
            mp[a[i]] = 1;
        }
    }
    for (auto x : mp) {
        if (x.second >= a.size() / 2) {
            return true;
        }
    }
    return false;
}
