bool areConsecutive(std::vector<int> arr, int n) {
    if (n < 1) {
        return false;
    }
    int Min = *min_element(arr.begin(), arr.end());
    int Max = *max_element(arr.begin(), arr.end());
    if (Max - Min + 1 == n) {
        std::vector<bool> visited(n, false);
        for (int i = 0; i < n; i++) {
            if (visited[arr[i] - Min] != false) {
                return false;
            }
            visited[arr[i] - Min] = true;
        }
        return true;
    }
    return false;
}
