#include <iostream>
#include <vector>
using namespace std;

int isPossible(int n, int index, int modulo, int M, vector<int>& arr, vector<vector<int>>& dp) {
    modulo = ((modulo % M) + M) % M;
    if (index == n) {
        if (modulo == 0) {
            return 1;
        }
        return 0;
    }
    if (dp[index][modulo] != -1) {
        return dp[index][modulo];
    }
    int placeAdd = isPossible(n, index + 1, modulo + arr[index], M, arr, dp);
    int placeMinus = isPossible(n, index + 1, modulo - arr[index], M, arr, dp);
    int res = (placeAdd || placeMinus) ? 1 : 0;
    dp[index][modulo] = res;
    return res;
}

int main() {
    int n = 5, index = 0, modulo = 0, M = 5;
    vector<int> arr = {1, 2, 3, 4, 5};
    vector<vector<int>> dp(n, vector<int>(M, -1));
    cout << isPossible(n, index, modulo, M, arr, dp) << endl;
    return 0;
}
```
