int countPairs(int arr[], int n) {
    std::unordered_map<int, int> mp;
    for (int i = 0; i < n; i++) {
        if (mp.find(arr[i]) != mp.end()) {
            mp[arr[i]] += 1;
        } else {
            mp[arr[i]] = 1;
        }
    }
    int ans = 0;
    for (auto it : mp) {
        int count = it.second;
        ans += (count * (count - 1)) / 2;
    }
    return ans;
}
