int countNumber(int n) {
    int result = 0;
    for (int i = 1; i < 10; i++) {
        std::stack<int> s;
        if (i <= n) {
            s.push(i);
            result++;
        }
        while (!s.empty()) {
            int tp = s.top();
            s.pop();
            for (int j = tp % 10; j < 10; j++) {
                int x = tp * 10 + j;
                if (x <= n) {
                    s.push(x);
                    result++;
                }
            }
        }
    }
    return result;
}
