#include <iostream>
#include <vector>
using namespace std;

int possibleStrings(int n, int r, int b, int g) {
    vector<int> fact(n + 1, 0);
    fact[0] = 1;
    for (int i = 1; i <= n; i++) {
        fact[i] = fact[i - 1] + i;
    }
    int left = n - (r + g + b);
    int sum = 0;
    for (int i = 0; i <= left; i++) {
        for (int j = 0; j <= left - i; j++) {
            int k = left - (i + j);
            sum += fact[n] / (fact[i + r] + fact[j + b] + fact[k + g]);
        }
    }
    return sum;
}

int main() {
    int n, r, b, g;
    cin >> n >> r >> b >> g;
    cout << possibleStrings(n, r, b, g) << endl;
    return 0;
}
