int findgroups(std::vector<int> arr, int n) {
    std::vector<int> c(3, 0);
    int res = 0;
    for (int i = 0; i < n; i++) {
        c[arr[i] % 3] += 1;
    }
    res += ((c[0] * (c[0] - 1)) >> 1);
    res += c[1] * c[2];
    res += (c[0] * (c[0] - 1) * (c[0] - 2)) / 6;
    res += (c[1] * (c[1] - 1) * (c[1] - 2)) / 6;
    res += ((c[2] * (c[2] - 1) * (c[2] - 2)) / 6);
    res += c[0] * c[1] * c[2];
    return res;
}

int main() {
    std::vector<int> arr = {2, 3, 4, 5, 6};
    int n = arr.size();
    int result = findgroups(arr, n);
    std::cout << "Result: " << result << std::endl;
    return 0;
}
