#include <iostream>
#include <vector>
#include <unordered_map>
using namespace std;

int countSubarrays(vector<int>& arr, int n) {
    int difference = 0;
    int ans = 0;
    unordered_map<int, int> hash_positive;
    unordered_map<int, int> hash_negative;
    hash_positive[0] = 1;
    for (int i = 0; i < n; i++) {
        if (arr[i] & 1) {
            difference++;
        } else {
            difference--;
        }
        if (difference < 0) {
            ans += hash_negative[-difference];
            hash_negative[-difference]++;
        } else {
            ans += hash_positive[difference];
            hash_positive[difference]++;
        }
    }
    return ans;
}

int main() {
    vector<int> arr = {2, 4, 6, 8, 10};
    int n = arr.size();
    cout << countSubarrays(arr, n) << endl;
    return 0;
}
