std::string decToBin(int n) {
    if (n == 0) {
        return "0";
    }
    std::string bin = "";
    while (n > 0) {
        if ((n & 1) == 0) {
            bin = '0' + bin;
        } else {
            bin = '1' + bin;
        }
        n = n >> 1;
    }
    return bin;
}

