std::string decode(std::string Str) {
    std::vector<int> integerstack;
    std::vector<char> stringstack;
    std::string temp = "";
    std::string result = "";
    for (int i = 0; i < Str.length(); i++) {
        int count = 0;
        if (Str[i] >= '0' && Str[i] <= '9') {
            while (Str[i] >= '0' && Str[i] <= '9') {
                count = count * 10 + Str[i] - '0';
                i++;
            }
            i--;
            integerstack.push_back(count);
        } else if (Str[i] == ']') {
            temp = "";
            count = 0;
            if (!integerstack.empty()) {
                count = integerstack.back();
                integerstack.pop_back();
            }
            while (!stringstack.empty() && stringstack.back() != '[') {
                temp = stringstack.back() + temp;
                stringstack.pop_back();
            }
            if (!stringstack.empty() && stringstack.back() == '[') {
                stringstack.pop_back();
            }
            for (int j = 0; j < count; j++) {
                result += temp;
            }
            for (int j = 0; j < result.length(); j++) {
                stringstack.push_back(result[j]);
            }
            result = "";
        } else if (Str[i] == '[') {
            if (i > 0 && Str[i - 1] >= '0' && Str[i - 1] <= '9') {
                stringstack.push_back(Str[i]);
            } else {
                stringstack.push_back(Str[i]);
                integerstack.push_back(1);
            }
        } else {
            stringstack.push_back(Str[i]);
        }
    }
    while (!stringstack.empty()) {
        result = stringstack.back() + result;
        stringstack.pop_back();
    }
    return result;
}

