int findWays(int m, int n, int x) {
    std::vector<std::vector<int>> table(n + 1, std::vector<int>(x + 1, 0));
    for (int j = 1; j < std::min(m + 1, x + 1); j++) {
        table[1][j] = 1;
    }
    for (int i = 2; i < n + 1; i++) {
        for (int j = 1; j < x + 1; j++) {
            for (int k = 1; k < std::min(m + 1, j); k++) {
                table[i][j] += table[i - 1][j - k];
            }
        }
    }
    return table.back().back();
}
