using namespace std;

int numberofways(int n, int m) {
    vector<vector<int>> dp(n + 2, vector<int>(n + 2, 0));
    dp[0][n + 1] = 1;
    for (int k = n; k >= m; k--) {
        for (int i = 0; i <= n; i++) {
            dp[i][k] = dp[i][k + 1];
            if (i - k >= 0) {
                dp[i][k] = (dp[i][k] + dp[i - k][k]);
            }
        }
    }
    return dp[n][m];
}
