#include <string>
using namespace std;

bool isDivisibleBy12(string num) {
    if (num.length() >= 3) {
        int d1 = num[num.length() - 1] - '0';
        if (d1 % 2 != 0) {
            return false;
        }
        int d2 = num[num.length() - 2] - '0';
        int sum = 0;
        for (int i = 0; i < num.length(); i++) {
            sum += num[i] - '0';
        }
        return (sum % 3 == 0 && (d2 * 10 + d1) % 4 == 0);
    } else {
        int number = stoi(num);
        return (number % 12 == 0);
    }
}

