#include <iostream>
#include <stack>
using namespace std;

bool findDuplicateparenthesis(string str) {
    stack<char> Stack;
    for (char ch : str) {
        if (ch == ')') {
            char top = Stack.top();
            int elementsInside = 0;
            Stack.pop();
            while (top != '(') {
                elementsInside++;
                top = Stack.top();
                Stack.pop();
            }
            if (elementsInside < 1) {
                return true;
            }
        } else {
            Stack.push(ch);
        }
    }
    return false;
}

int main() {
    string input = "((a+b)+((c+d)))";
    if (findDuplicateparenthesis(input)) {
        cout << "Duplicate parenthesis found" << endl;
    } else {
        cout << "No duplicate parenthesis found" << endl;
    }
    return 0;
}
