#include <map>
#include <cmath>

int findFourElements(std::vector<int>& arr, int n) {
    std::map<int, std::pair<int, int>> mp;
    for (int i = 0; i < n - 1; i++) {
        for (int j = i + 1; j < n; j++) {
            mp[arr[i] + arr[j]] = std::make_pair(i, j);
        }
    }
    int d = -1e9;
    for (int i = 0; i < n - 1; i++) {
        for (int j = i + 1; j < n; j++) {
            int abs_diff = std::abs(arr[i] - arr[j]);
            if (mp.count(abs_diff) > 0) {
                std::pair<int, int> p = mp[abs_diff];
                if (p.first != i && p.first != j && p.second != i && p.second != j) {
                    d = std::max(d, std::max(arr[i], arr[j]));
                }
            }
        }
    }
    return d;
}

int main() {
    std::vector<int> arr = {1, 2, 3, 4, 5};
    int n = arr.size();
    std::cout << findFourElements(arr, n) << std::endl;
    return 0;
}
