int findMin(vector<int>& arr, int low, int high) {
    if (high < low) {
        return arr[0];
    }
    if (high == low) {
        return arr[low];
    }
    int mid = (low + high) / 2;
    if (mid < high && arr[mid + 1] < arr[mid]) {
        return arr[mid + 1];
    }
    if (mid > low && arr[mid] < arr[mid - 1]) {
        return arr[mid];
    }
    if (arr[high] > arr[mid]) {
        return findMin(arr, low, mid - 1);
    }
    return findMin(arr, mid + 1, high);
}

int main() {
    vector<int> arr = {5, 6, 7, 8, 9, 10, 1, 2, 3};
    int n = arr.size();
    int minValue = findMin(arr, 0, n - 1);
    cout << "The minimum value is " << minValue;
    return 0;
}
