    std::vector<int> count(high + 1, 0);
    for (int i = 0; i < n; i++) {
        count[arr[i]] += 1;
    }
    int counter = 0;
    for (int i = high; i > 0; i--) {
        int j = i;
        while (j <= high) {
            if (count[j] > 0) {
                counter += count[j];
