std::string getMinNumberForPattern(std::string seq) {
    int n = seq.size();
    if (n >= 9) {
        return "-1";
    }
    std::vector<int> result(n + 1, 0);
    int count = 1;
    for (int i = 0; i < n + 1; i++) {
        if (i == n || seq[i] == 'I') {
            for (int j = i - 1; j >= -1; j--) {
                result[j + 1] = std::stoi("0" + std::to_string(count));
                count++;
                if (j >= 0 && seq[j] == 'I') {
                    break;
                }
            }
        }
    }
    std::string output;
    for (int i : result) {
        output += std::to_string(i);
    }
    return output;
}

int main() {
    std::string input = "IDID";
    std::cout << getMinNumberForPattern(input) << std::endl;
    return 0;
}
