    vector<vector<int>> dp(n + 1, vector<int>(10, 0));
    vector<int> arr(n + 1, 0);
    for (int i = 1; i <= n; i++) {
        arr[i] = str[i - 1] - '0';
    }
    for (int i = 1; i <= n; i++) {
        dp[i][arr[i] % 8] = 1;
        for (int j = 0; j < 8; j++) {
            if (dp[i - 1][j] > dp[i][(j * 10 + arr[i]) % 8]) {
                dp[i][(j * 10 + arr[i]) % 8] = dp[i - 1][j];
            }
            if (dp[i - 1][j] > dp[i][j]) {
                dp[i][j] = dp[i - 1][j];
            }
        }
    }
    for (int i = 1; i <= n; i++) {
        if (dp[i][0] == 1) {
            return true;
        }
    }
    return false;
