    while (index < n) {
        if (index == 0) {
            index = index + 1;
        }
        if (arr[index] >= arr[index - 1]) {
            index = index + 1;
        } else {
            std::swap(arr[index], arr[index - 1]);
            index = index - 1;
        }
    }
    return arr;
}
