int exactPrimeFactorCount(int n) {
    int count = 0;
    if (n % 2 == 0) {
        count += 1;
        while (n % 2 == 0) {
            n = n / 2;
        }
    }
    int i = 3;
    while (i <= sqrt(n)) {
        if (n % i == 0) {
            count += 1;
            while (n % i == 0) {
                n = n / i;
            }
        }
        i += 2;
    }
    if (n > 2) {
        count += 1;
    }
    return count;
}

int main() {
    int n = 100;
    std::cout << exactPrimeFactorCount(n) << std::endl;
    return 0;
