#include <algorithm>

int findoptimal(int N) {
    if (N <= 6) {
        return N;
    }
    std::vector<int> screen(N, 0);
    for (int n = 1; n <= 6; ++n) {
        screen[n - 1] = n;
    }
    for (int n = 7; n <= N; ++n) {
        screen[n - 1] = std::max(2 * screen[n - 4], std::max(3 * screen[n - 5], 4 * screen[n - 6]));
    }
    return screen[N - 1];
}

int main() {
    int N;
    std::cout << "Enter the value of N: ";
    std::cin >> N;
    std::cout << "Optimal value: " << findoptimal(N) << std::endl;
    return 0;
}
