#include <unordered_map>
#include <vector>
#include <cmath>

int findInteger(std::vector<int>& arr, int n) {
    std::unordered_map<int, int> hash;
    int maximum = 0;
    for (int i : arr) {
        if (i < 0) {
            if (hash.find(std::abs(i)) == hash.end()) {
                hash[std::abs(i)] = -1;
            } else {
                hash[std::abs(i)] -= 1;
            }
        } else {
            hash[i] = hash.find(i) != hash.end() ? hash[i] + 1 : 1;
        }
    }
    for (int i : arr) {
        if (hash.find(i) != hash.end() && hash[i] > 0) {
            return i;
        }
    }
    return -1;
}
