int kthLargestSum (vector<int>& arr, int n, int k) {
    vector<int> sum;
    sum.push_back(0);
    sum.push_back(arr[0]);
    for (int i = 2; i <= n; i++) {
        sum.push_back(sum[i - 1] + arr[i - 1]);
    }
    priority_queue<int, vector<int>, greater<int>> Q;
    for (int i = 1; i <= n; i++) {
        for (int j = i; j <= n; j++) {
            int x = sum[j] - sum[i - 1];
            if (Q.size() < k) {
                Q.push(x);
            } else {
                if (Q.top() < x) {
                    Q.pop();
                    Q.push(x);
                }
            }
        }
    }
    return Q.top();
}
