        if (hash_map.find(curr_sum + n) != hash_map.end()) {
            if (max_len < i - hash_map[curr_sum + n]) {
                max_len = i - hash_map[curr_sum + n];
                ending_index = i;
            }
        } else {
            hash_map[curr_sum + n] = i;
        }
    }

    for (int i = 0; i < n; i++) {
        if (arr[i] == -1) {
            arr[i] = 0;
        } else {
            arr[i] = 1;
        }
    }

    cout << ending_index - max_len + 1 << " to " << ending_index << endl;

    return max_len;
}

int main() {
    int arr[] = {0, 1, 0, 0, 1, 0, 1, 1};
    int n = sizeof(arr) / sizeof(arr[0]);
    cout << "Maximum length of subarray with equal 0s and 1s is " << maxLen(arr, n) << endl;
    return 0;
}
