int longestSubsequenceCommonSegment(int k, string s1, string s2) {
    int n = s1.length();
    int m = s2.length();
    vector<vector<int>> lcs(n + 1, vector<int>(m + 1, 0));
    vector<vector<int>> cnt(n + 1, vector<int>(m + 1, 0));

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            lcs[i][j] = max(lcs[i - 1][j], lcs[i][j - 1]);
            if (s1[i - 1] == s2[j - 1]) {
                cnt[i][j] = cnt[i - 1][j - 1] + 1;
            }
            if (cnt[i][j] >= k) {
                for (int a = k; a <= cnt[i][j]; a++) {
                    lcs[i][j] = max(lcs[i][j], lcs[i - a][j - a] + a);
                }
            }
        }
    }

    return lcs[n][m];
}

int main() {
    int k = 2;
    string s1 = "abcde";
    string s2 = "ace";
    cout << longestSubsequenceCommonSegment(k, s1, s2) << endl;
    return 0;
}

