    for (int i = 0; i < S.length(); i++) {
        arr.push_back(std::make_pair(S[i], i));
        while (arr.size() >= 3 && arr[arr.size() - 3].first == '1' && arr[arr.size() - 2].first == '0' && arr[arr.size() - 1].first == '0') {
            arr.pop_back();
            arr.pop_back();
            arr.pop_back();
        }
        std::pair<char, int> tmp = arr.back();
        maxlen = std::max(maxlen, i - tmp.second);
    }
    return maxlen;
}

int main() {
    std::string S = "1010011000100";
    std::cout << longestNull(S) << std::endl;
    return 0;
}
