bool prevPermutation(string str) {
    int n = str.length() - 1;
    int i = n;
    while (i > 0 && str[i - 1] <= str[i]) {
        i--;
    }
    if (i <= 0) {
        return false;
    }
    int j = i - 1;
    while (j + 1 <= n && str[j + 1] <= str[i - 1]) {
        j++;
    }
    char temp = str[i - 1];
    str[i - 1] = str[j];
    str[j] = temp;
    for(int k = 0; k < (n-i+1)/2; k++) {
        char temp = str[i+k];
        str[i+k] = str[n-k];
        str[n-k] = temp;
    }
    return true;
}
