void minimizeWithKSwaps(int arr[], int n, int k) {
    for (int i = 0; i < n - 1; i++) {
        int pos = i;
        for (int j = i + 1; j < n; j++) {
            if (j - i > k) {
                break;
            }
            if (arr[j] < arr[pos]) {
                pos = j;
            }
        }
        for (int j = pos; j > i; j--) {
            swap(arr[j], arr[j - 1]);
        }
        k -= pos - i;
    }
}

int main() {
    int arr[] = {3, 1, 4, 2, 5};
    int n = 5;
    int k = 2;
    minimizeWithKSwaps(arr, n, k);
    for (int i = 0; i < n; i++) {
        cout << arr[i] << " ";
    }
    return 0;
}
