std::string lexicographicSubConcat(std::string s) {
    int n = s.length();
    int sub_count = (n * (n + 1)) / 2;
    std::vector<std::string> arr(sub_count, "");
    int index = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 1; j <= n - i; j++) {
            arr[index] = s.substr(i, j);
            index++;
        }
    }
    std::sort(arr.begin(), arr.end());
    std::string res = "";
    for (int i = 0; i < sub_count; i++) {
        res += arr[i];
    }
    return res;
}
