#include <iostream>
#include <vector>
using namespace std;

int lcs(vector<vector<vector<int>>> &dp, vector<int> &arr1, int n, vector<int> &arr2, int m, int k) {
    if (k < 0) {
        return - (int)1e7;
    }
    if (n < 0 || m < 0) {
        return 0;
    }
    int &ans = dp[n][m][k];
    if (ans != -1) {
        return ans;
    }
    ans = max(lcs(dp, arr1, n - 1, arr2, m, k), lcs(dp, arr1, n, arr2, m - 1, k));
    if (arr1[n - 1] == arr2[m - 1]) {
        ans = max(ans, 1 + lcs(dp, arr1, n - 1, arr2, m - 1, k));
    }
    ans = max(ans, lcs(dp, arr1, n - 1, arr2, m - 1, k - 1));
    return ans;
}

int main() {
    int n, m, k;
    // Input values for n, m, k
    vector<int> arr1(n), arr2(m);
    // Input values for arr1 and arr2
    vector<vector<vector<int>>> dp(n + 1, vector<vector<int>>(m + 1, vector<int>(k + 1, -1)));
    int longestCommonSubsequence = lcs(dp, arr1, n, arr2, m, k);
    cout << longestCommonSubsequence << endl;
    return 0;
}
