#include <iostream>
#include <string>
#include <vector>
using namespace std;

int longestPrefixSuffix(string s) {
    int n = s.length();
    vector<int> lps(n, 0);
    int l = 0, i = 1;
    while (i < n) {
        if (s[i] == s[l]) {
            l++;
            lps[i] = l;
            i++;
        } else {
            if (l != 0) {
                l = lps[l - 1];
            } else {
                lps[i] = 0;
                i++;
            }
        }
