using namespace std;

string longestRepeatedSubSeq(string str) {
    int n = str.length();
    int dp[n + 1][n + 1];
    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= n; j++) {
            dp[i][j] = 0;
        }
    }
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            if (str[i - 1] == str[j - 1] && i != j) {
                dp[i][j] = 1 + dp[i - 1][j - 1];
            } else {
                dp[i][j] = max(dp[i][j - 1], dp[i - 1][j]);
            }
        }
    }
    string res = "";
    int i = n, j = n;
    while (i > 0 && j > 0) {
        if (dp[i][j] == dp[i - 1][j - 1] + 1) {
            res += str[i - 1];
            i -= 1;
            j -= 1;
        } else if (dp[i][j] == dp[i - 1][j]) {
            i -= 1;
        } else {
            j -= 1;
        }
    }
    reverse(res.begin(), res.end());
    return res;
}

int main() {
    string str = "abba";
    cout << longestRepeatedSubSeq(str) << endl;
    return 0;
}
