    unordered_map<int, int> um;
    int sum = 0;
    int maxLen = 0;
    for (int i = 0; i < n; i++) {
        if (arr[i] == 0) {
            sum += -1;
        } else {
            sum += 1;
        }
        if (sum == 1) {
            maxLen = i + 1;
        } else if (um.find(sum) == um.end()) {
            um[sum] = i;
        }
        if (um.find(sum - 1) != um.end()) {
            if (maxLen < (i - um[sum - 1])) {
                maxLen = i - um[sum - 1];
            }
        }
    }
    return maxLen;
}

