#include <iostream>
#include <string>
#include <algorithm>

std::string maximumPalinUsingKChanges(std::string str, int k) {
    std::string palin = str;
    int l = 0;
    int r = str.length() - 1;
    while (l <= r) {
        if (str[l] != str[r]) {
            palin[l] = palin[r] = std::max(str[l], str[r]);
            k--;
        }
        l++;
        r--;
    }
    if (k < 0) {
        return "Not possible";
    }
    l = 0;
    r = str.length() - 1;
    while (l <= r) {
        if (l == r) {
            if (k > 0) {
                palin[l] = '9';
            }
        }
        if (palin[l] < '9') {
            if (k >= 2 && palin[l] == str[l] && palin[r] == str[r]) {
                k--;
                palin[l] = palin[r] = '9';
            } else if (k >= 1 && (palin[l] != str[l] || palin[r] != str[r])) {
                k--;
                palin[l] = palin[r] = '9';
            }
        }
        l++;
        r--;
    }
    return palin;
}

int main() {
    std::string str = "12321";
    int k = 1;
    std::cout << maximumPalinUsingKChanges(str, k) << std::endl;
    return 0;
}
