#include <vector>
using namespace std;

int findMaxVal(vector<int>& arr, int n, int num, int maxLimit) {
    int ind = -1;
    int val = -1;
    vector<vector<int>> dp(n, vector<int>(maxLimit + 1, 0));
    for (ind = 0; ind < n; ind++) {
        for (val = 0; val < maxLimit + 1; val++) {
            if (ind == 0) {
                if (num - arr[ind] == val || num + arr[ind] == val) {
                    dp[ind][val] = 1;
                } else {
                    dp[ind][val] = 0;
                }
            } else {
                if (val - arr[ind] >= 0 && val + arr[ind] <= maxLimit) {
                    if (dp[ind - 1][val - arr[ind]] == 1 || dp[ind - 1][val + arr[ind]] == 1) {
                        dp[ind][val] = 1;
                    }
                } else if (val - arr[ind] >= 0) {
                    dp[ind][val] = dp[ind - 1][val - arr[ind]];
                } else if (val + arr[ind] <= maxLimit) {
                    dp[ind][val] = dp[ind - 1][val + arr[ind]];
                } else {
                    dp[ind][val] = 0;
                }
            }
        }
    }
    for (val = maxLimit; val >= 0; val--) {
        if (dp[n - 1][val] == 1) {
            return val;
        }
    }
    return -1;
}
