#include <vector>
#include <algorithm>

int largestSumOfAverages(std::vector<int>& A, int K) {
    int n = A.size();
    std::vector<int> pre_sum(n + 1, 0);
    for (int i = 0; i < n; i++) {
        pre_sum[i + 1] = pre_sum[i] + A[i];
    }
    std::vector<double> dp(n, 0);
    for (int i = 0; i < n; i++) {
        dp[i] = static_cast<double>(pre_sum[n] - pre_sum[i]) / (n - i);
    }
    for (int k = 0; k < K - 1; k++) {
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                dp[i] = std::max(dp[i], (static_cast<double>(pre_sum[j] - pre_sum[i]) / (j - i)) + dp[j]);
            }
        }
    }
    return static_cast<int>(dp[0]);
}
