using namespace std;

int findLongestConseqSubseq(int arr[], int n) {
    unordered_set<int> S;
    for (int i = 0; i < n; i++) {
        S.insert(arr[i]);
    }
    int ans = 0;
    for (int i = 0; i < n; i++) {
        if (S.find(arr[i]) != S.end()) {
            int j = arr[i];
            while (S.find(j) != S.end()) {
                j++;
            }
            ans = max(ans, j - arr[i]);
        }
    }
    return ans;
}

int main() {
    int arr[] = {5, 2, 3, 6, 4, 4, 6, 6, 7, 8};
    int n = sizeof(arr) / sizeof(arr[0]);
    int result = findLongestConseqSubseq(arr, n);
    cout << "Length of the longest consecutive subsequence is: " << result << endl;
    return 0;
}
