int maxNumOfChocolates(vector<int>& arr, int n, int k) {
    unordered_map<int, int> um;
    int curr_rem, maxSum = 0;
    vector<int> sm(n, 0);
    sm[0] = arr[0];
    for (int i = 1; i < n; i++) {
        sm[i] = sm[i - 1] + arr[i];
    }
    for (int i = 0; i < n; i++) {
        curr_rem = sm[i] % k;
        if (!curr_rem && maxSum < sm[i]) {
            maxSum = sm[i];
        } else if (um.find(curr_rem) == um.end()) {
            um[curr_rem] = i;
        } else if (maxSum < (sm[i] - sm[um[curr_rem]])) {
            maxSum = sm[i] - sm[um[curr_rem]];
        }
    }
    return maxSum / k;
}
