        else if (um.find(curr_rem) == um.end()) {
            um[curr_rem] = i;
        }
        else if (maxSum < (sm[i] - sm[um[curr_rem]])) {
            maxSum = sm[i] - sm[um[curr_rem]];
        }
    }
    return maxSum / k;
}
