        if (isSingleOccurance == true) {
            if (arr[i] > 0) {
                SubsetSum_1 += arr[i];
            } else {
                SubsetSum_2 += arr[i];
            }
        }
    }
    return std::abs(SubsetSum_1 - SubsetSum_2);
}

