        return arr[0];
    }
    vector<int> dec(n + 1, 0);
    vector<int> inc(n + 1, 0);
    dec[0] = inc[0] = arr[0];
    int flag = 0;
    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (arr[j] > arr[i]) {
                dec[i] = max(dec[i], inc[j] + arr[i]);
                flag = 1;
            } else if (arr[j] < arr[i] && flag == 1) {
                inc[i] = max(inc[i], dec[j] + arr[i]);
            }
        }
    }
    int result = -2147483648;
    for (int i = 0; i < n; i++) {
        if (result < inc[i]) {
            result = inc[i];
        }
        if (result < dec[i]) {
            result = dec[i];
        }
    }
    return result;
