int maxSumSubarrayRemovingOneEle(std::vector<int>& arr, int n) {
    std::vector<int> fw(n, 0);
    std::vector<int> bw(n, 0);
    int cur_max = arr[0];
    int max_so_far = arr[0];

    for (int i = 1; i < n; i++) {
        cur_max = std::max(arr[i], cur_max + arr[i]);
        max_so_far = std::max(max_so_far, cur_max);
        fw[i] = cur_max;
    }

    cur_max = max_so_far = bw[n - 1] = arr[n - 1];
