int maxCost(std::vector<std::vector<int>>& mat, int N) {
    std::vector<std::vector<int>> dp(N, std::vector<int>(N, 0));
    dp[0][0] = mat[0][0];
    for (int i = 1; i < N; i++) {
        dp[i][0] = mat[i][0] + dp[i - 1][0];
    }
    for (int i = 1; i < N; i++) {
        for (int j = 1; j < std::min(i + 1, N); j++) {
            dp[i][j] = mat[i][j] + std::max(dp[i - 1][j - 1], dp[i - 1][j]);
        }
    }
    int result = 0;
    for (int i = 0; i < N; i++) {
        if (result < dp[N - 1][i]) {
            result = dp[N - 1][i];
        }
    }
    return result;
}
