    int j = 0;
    int m1 = -1;
    int m2 = -1;
    int count = 0;
    while (count < n + 1) {
        count += 1;
        if (i == n) {
            m1 = m2;
            m2 = ar2[0];
            break;
        } else if (j == n) {
            m1 = m2;
            m2 = ar1[0];
            break;
        }
        if (ar1[i] < ar2[j]) {
            m1 = m2;
            m2 = ar1[i];
            i += 1;
        } else {
            m1 = m2;
            m2 = ar2[j];
            j += 1;
        }
    }
    return (m1 + m2) / 2;
}

