int minValue(int A[], int B[], int n) {
    std::sort(A, A + n);
    std::sort(B, B + n);
    int result = 0;
    for (int i = 0; i < n; i++) {
        result += (A[i] * B[n - i - 1]);
    }
    return result;
}

int main() {
    int A[] = {2, 3, 4};
    int B[] = {1, 5, 6};
    int n = 3;
    std::cout << minValue(A, B, n) << std::endl;
    return 0;
}
