#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
using namespace std;

int solve(string X, string Y, int l, int r, int k, vector<vector<vector<int>>>& dp) {
    if (k == 0) {
        return 0;
    }
    if (l < 0 || r < 0) {
        return 1000000000;
    }
    if (dp[l][r][k] != -1) {
        return dp[l][r][k];
    }
    int cost = ((int(X[l]) - int('a')) ^ (int(Y[r]) - int('a')));
    dp[l][r][k] = min({cost + solve(X, Y, l - 1, r - 1, k - 1, dp),
                       solve(X, Y, l - 1, r, k, dp),
                       solve(X, Y, l, r - 1, k, dp)});
    return dp[l][r][k];
}

int main() {
    string X = "exampleX";
    string Y = "exampleY";
    int l = X.size() - 1;
    int r = Y.size() - 1;
    int k = 3;
    vector<vector<vector<int>>> dp(l + 1, vector<vector<int>>(r + 1, vector<int>(k + 1, -1)));
    cout << solve(X, Y, l, r, k, dp) << endl;
    return 0;
}
