int minJumps(std::vector<int>& arr, int n) {
    std::vector<int> jumps(n, 0);
    for (int i = n - 2; i >= 0; i--) {
        if (arr[i] == 0) {
            jumps[i] = std::numeric_limits<int>::max();
        } else if (arr[i] >= n - i - 1) {
            jumps[i] = 1;
        } else {
            int min = std::numeric_limits<int>::max();
            for (int j = i + 1; j < n; j++) {
                if (j <= arr[i] + i) {
                    if (min > jumps[j]) {
                        min = jumps[j];
                    }
                }
            }
            if (min != std::numeric_limits<int>::max()) {
                jumps[i] = min + 1;
            } else {
                jumps[i] = min;
            }
        }
    }
    return jumps[0];
}
