int getMinSquares(int n) {
    vector<int> dp{0, 1, 2, 3};
    for (int i = 4; i <= n; i++) {
        dp.push_back(i);
        for (int x = 1; x <= static_cast<int>(ceil(sqrt(i))); x++) {
            int temp = x * x;
            if (temp > i) {
                break;
            } else {
