#include <iostream>
#include <vector>
#include <climits>

using namespace std;

int minProductSubset(vector<int> a, int n) {
    if (n == 1) {
        return a[0];
    }
    int max_neg = INT_MIN;
    int min_pos = INT_MAX;
    int count_neg = 0;
    int count_zero = 0;
    int prod = 1;
    for (int i = 0; i < n; i++) {
        if (a[i] == 0) {
            count_zero++;
            continue;
        }
        if (a[i] < 0) {
            count_neg++;
            max_neg = max(max_neg, a[i]);
        }
        if (a[i] > 0) {
            min_pos = min(min_pos, a[i]);
        }
        prod *= a[i];
    }
    if (count_zero == n || (count_neg == 0 && count_zero > 0)) {
        return 0;
    }
    if (count_neg == 0) {
        return min_pos;
    }
    if ((count_neg & 1) == 0 && count_neg != 0) {
        prod = prod / max_neg;
    }
    return prod;
}

int main() {
    vector<int> a = {2, -3, 1, 0, -5};
    int n = a.size();
    cout << minProductSubset(a, n) << endl;
    return 0;
}
