        if (a[i] > 0) {
            min_pos = std::min(min_pos, a[i]);
        }
        prod *= a[i];
    }

    if (count_zero == n || (count_neg == 0 && count_zero > 0)) {
        return 0;
    }
    if (count_neg == 0) {
        return min_pos;
    }
    if ((count_neg % 2) == 0 && count_neg != 0) {
        prod = prod / max_neg;
    }

    return prod;
}

int main() {
    std::vector<int> a = {2, -3, 4, -2, 6};
    int n = a.size();
    std::cout << minProductSubset(a, n) << std::endl;

