    if (count_zero == n || (count_neg == 0 && count_zero > 0)) {
        return 0;
    }
    if (count_neg == 0) {
        return min_pos;
    }
    if ((count_neg & 1) == 0 && count_neg != 0) {
        prod = prod / max_neg;
    }

    return prod;
}

