int minSum(std::vector<int> arr, int n) {
    std::vector<int> dp(n, 0);
    if (n == 1) {
        return arr[0];
    }
    if (n == 2) {
        return std::min(arr[0], arr[1]);
    }
    if (n == 3) {
        return std::min(arr[0], std::min(arr[1], arr[2]));
    }
    if (n == 4) {
        return std::min(std::min(arr[0], arr[1]), std::min(arr[2], arr[3]));
    }
    dp[0] = arr[0];
    dp[1] = arr[1];
    dp[2] = arr[2];
    dp[3] = arr[3];
    for (int i = 4; i < n; i++) {
        dp[i] = arr[i] + std::min(std::min(dp[i - 1], dp[i - 2]), std::min(dp[i - 3], dp[i - 4]));
    }
    return std::min(std::min(dp[n - 1], dp[n - 2]), std::min(dp[n - 4], dp[n - 3]));
}
