unsigned int snoob(unsigned int x) {
    unsigned int next = 0;
    if (x) {
        unsigned int rightOne = x & -x;
        unsigned int nextHigherOneBit = x + rightOne;
        unsigned int rightOnesPattern = x ^ nextHigherOneBit;
        rightOnesPattern = rightOnesPattern / rightOne;
        rightOnesPattern = rightOnesPattern >> 2;
        next = nextHigherOneBit | rightOnesPattern;
    }
    return next;
}
