#include <vector>
#include <string>

int countDivisibleSubseq(std::string str, int n) {
    int l = str.length();
    std::vector<std::vector<int>> dp(l, std::vector<int>(n, 0));
    dp[0][(str[0] - '0') % n] += 1;
    for (int i = 1; i < l; i++) {
        dp[i][(str[i] - '0') % n] += 1;
        for (int j = 0; j < n; j++) {
            dp[i][j] += dp[i - 1][j];
            dp[i][(j * 10 + (str[i] - '0')) % n] += dp[i - 1][j];
        }
    }
    return dp[l - 1][0];
}
