int minimumBox(int arr[], int n) {
    std::deque<int> q;
    std::sort(arr, arr + n);
    q.push_back(arr[0]);
    for (int i = 1; i < n; i++) {
        int now = q.front();
        if (arr[i] >= 2 * now) {
            q.pop_front();
        }
        q.push_back(arr[i]);
    }
    return q.size();
}
