int maximumNumberDistinctPrimeRange(int m, int n) {
    std::vector<int> factorCount(n + 1, 0);
    std::vector<bool> prime(n + 1, true);

    for (int i = 2; i <= n; i++) {
        if (prime[i]) {
            factorCount[i] = 1;
            for (int j = i * 2; j <= n; j += i) {
                factorCount[j]++;
                prime[j] = false;
            }
        }
    }

    int max = factorCount[m];
    int num = m;
    for (int i = m; i <= n; i++) {
        if (factorCount[i] > max) {
            max = factorCount[i];
            num = i;
        }
    }

    return num;
}
