bool checkPangram(string s) {
    bool List[26] = {false};
    for (char c : s) {
        if ('A' <= c && c <= 'Z') {
            List[c - 'A'] = true;
        } else if ('a' <= c && c <= 'z') {
            List[c - 'a'] = true;
        }
    }
    for (bool ch : List) {
        if (!ch) {
            return false;
        }
