int maxDifference(vector<int> arr, int N, int k) {
    int S = 0;
    int S1 = 0;
    int max_difference = 0;
    for (int i = 0; i < N; i++) {
        S += arr[i];
    }
    sort(arr.begin(), arr.end(), greater<int>());
    int M = max(k, N - k);
    for (int i = 0; i < M; i++) {
        S1 += arr[i];
    }
    max_difference = S1 - (S - S1);
    return max_difference;
}
