void antiSpiralTraversal(int m, int n, std::vector<std::vector<int>> a) {
    int k = 0;
    int l = 0;
    std::vector<int> stk;
    while (k <= m && l <= n) {
        for (int i = l; i <= n; i++) {
            stk.push_back(a[k][i]);
        }
        k++;
        for (int i = k; i <= m; i++) {
            stk.push_back(a[i][n]);
        }
        n--;
        if (k <= m) {
            for (int i = n; i >= l; i--) {
                stk.push_back(a[m][i]);
            }
            m--;
        }
        if (l <= n) {
            for (int i = m; i >= k; i--) {
                stk.push_back(a[i][l]);
            }
            l++;
        }
    }
    while (!stk.empty()) {
        std::cout << stk.back() << " ";
        stk.pop_back();
    }
}

