void printSpiral(std::vector<std::vector<int>> &mat, int r, int c) {
    int a = 0;
    int b = 2;
    int low_row = (0 > a) ? 0 : a;
    int low_column = (0 > b) ? 0 : b - 1;
    int high_row = ((a + 1) >= r) ? r - 1 : a + 1;
    int high_column = ((b + 1) >= c) ? c - 1 : b + 1;

    while ((low_row > 0 - r && low_column > 0 - c)) {
        int i = low_column + 1;
        while (i <= high_column && i < c && low_row >= 0) {
            std::cout << mat[low_row][i] << " ";
            i++;
        }
        low_row -= 1;

        i = low_row + 2;
        while (i <= high_row && i < r && high_column < c) {
            std::cout << mat[i][high_column] << " ";
            i++;
        }
        high_column += 1;

        i = high_column - 2;
        while (i >= low_column && i >= 0 && high_row < r) {
            std::cout << mat[high_row][i] << " ";
            i--;
        }
        high_row += 1;

        i = high_row - 2;
        while (i > low_row && i >= 0 && low_column >= 0) {
            std::cout << mat[i][low_column] << " ";
            i--;
        }
        low_column -= 1;
    }

    std::cout << std::endl;
}

