#include <unordered_map>
#include <algorithm>
#include <climits>

int find_maximum(int a[], int n, int k) {
    std::unordered_map<int, int> b;
    for (int i = 0; i < n; i++) {
        int x = a[i];
        int d = std::min(1 + i, n - i);
        if (b.find(x) == b.end()) {
            b[x] = d;
        } else {
            b[x] = std::min(d, b[x]);
        }
    }
    int ans = INT_MAX;
    for (int i = 0; i < n; i++) {
        int x = a[i];
        if (x != (k - x) && b.find(k - x) != b.end()) {
            ans = std::min(std::max(b[x], b[k - x]), ans);
        }
    }
    return ans;
}
