bool isValidISBN(string isbn) {
    if (isbn.length() != 10) {
        return false;
    }
    int _sum = 0;
    for (int i = 0; i < 9; i++) {
        if (isdigit(isbn[i])) {
            _sum += (isbn[i] - '0') * (10 - i);
        } else {
            return false;
        }
    }
    if (isbn[9] != 'X' && isdigit(isbn[9])) {
        return false;
    }
    _sum += (isbn[9] == 'X' ? 10 : (isbn[9] - '0'));
    return (_sum % 11 == 0);
}

int main() {
    string isbn = "0375727349";
    cout << isValidISBN(isbn) << endl;  // Output based on the example input
    return 0;
}
