void worstFit(std::vector<int>& blockSize, int m, std::vector<int>& processSize, int n) {
    std::vector<int> allocation(n, -1);

    for (int i = 0; i < n; ++i) {
        int wstIdx = -1;
        for (int j = 0; j < m; ++j) {
            if (blockSize[j] >= processSize[i]) {
                if (wstIdx == -1) {
                    wstIdx = j;
                } else if (blockSize[wstIdx] < blockSize[j]) {
                    wstIdx = j;
                }
            }
        }

        if (wstIdx != -1) {
            allocation[i] = wstIdx;
            blockSize[wstIdx] -= processSize[i];
        }
    }

    std::cout << "Process No. Process Size Block no.\n";
    for (int i = 0; i < n; ++i) {
        std::cout << i + 1 << "         " << processSize[i] << "     ";
        if (allocation[i] != -1) {
            std::cout << allocation[i] + 1;
        } else {
            std::cout << "Not Allocated";
        }
        std::cout << std::endl;
    }
}

int main() {
    std::vector<int> blockSize = {100, 500, 200, 300, 600};
    std::vector<int> processSize = {212, 417, 112, 426};
    int m = blockSize.size();
    int n = processSize.size();

    worstFit(blockSize, m, processSize, n);

    return 0;
}
