#include <iostream>
#include <string>
#include <vector>
using namespace std;

string simplify(string Str) {
    int Len = Str.length();
    vector<char> res(Len, ' ');
    int index = 0;
    int i = 0;
    vector<int> s;
    s.push_back(0);

    while (i < Len) {
        if (Str[i] == '+') {
            if (s.back() == 1) {
                res[index] = '-';
                index++;
            }
            if (s.back() == 0) {
                res[index] = '+';
                index++;
            }
        } else if (Str[i] == '-') {
            if (s.back() == 1) {
                res[index] = '+';
                index++;
            } else if (s.back() == 0) {
                res[index] = '-';
                index++;
            }
        } else if (Str[i] == '(' && i > 0) {
            if (Str[i - 1] == '-') {
                int x = (s.back() == 1) ? 0 : 1;
                s.push_back(x);
            } else if (Str[i - 1] == '+') {
                s.push_back(s.back());
            }
        } else if (Str[i] == ')') {
            s.pop_back();
        } else {
            res[index] = Str[i];
            index++;
        }
        i++;
    }

    string result(res.begin(), res.end());
    return result;
}

int main() {
    string input = "-(+-)+-";
    string output = simplify(input);
    cout << output << endl;
    return 0;
}
