int insertSorted(int arr[], int n, int key, int capacity) {
    if (n >= capacity) {
        return n;
    }
    int i = n - 1;
    while (i >= 0 && arr[i] > key) {
        arr[i + 1] = arr[i];
        i--;
    }
    arr[i + 1] = key;
    return (n + 1);
}
