void bitonicGenerator(std::vector<int>& arr, int n) {
    std::vector<int> evenArr, oddArr;
    for (int i = 0; i < n; ++i) {
        if (i % 2 == 0) {
            evenArr.push_back(arr[i]);
        } else {
            oddArr.push_back(arr[i]);
        }
    }
    std::sort(evenArr.begin(), evenArr.end());
    std::sort(oddArr.begin(), oddArr.end());
    std::reverse(oddArr.begin(), oddArr.end());
    int i = 0;
    for (int j = 0; j < evenArr.size(); ++j) {
        arr[i] = evenArr[j];
        i++;
    }
    for (int j = 0; j < oddArr.size(); ++j) {
        arr[i] = oddArr[j];
        i++;
    }
}
