#include <iostream>
#include <vector>
using namespace std;

int KnapSack(vector<int>& val, vector<int>& wt, int n, int W) {
    vector<vector<int>> mat(2, vector<int>(W + 1, 0));
    int i = 0;
    while (i < n) {
        int j = 0;
        if (i % 2 == 0) {
            while (j < W) {
                j += 1;
                if (wt[i] <= j && j - wt[i] < W) {
                    mat[1][j] = max(val[i] + mat[0][j - wt[i]], mat[0][j]);
                } else {
                    mat[1][j] = mat[0][j];
                }
            }
        } else {
            while (j < W) {
                j += 1;
                if (wt[i] <= j && j - wt[i] < W) {
                    mat[0][j] = max(val[i] + mat[1][j - wt[i]], mat[1][j]);
                } else {
                    mat[0][j] = mat[1][j];
                }
            }
        }
        i += 1;
    }
    if (n % 2 == 0) {
        return mat[0][W];
    } else {
        return mat[1][W];
    }
}
