#include <vector>
#include <algorithm>

int KnapSack(std::vector<int>& val, std::vector<int>& wt, int n, int W) {
    std::vector<int> dp(W + 1, 0);
    for (int i = 0; i < n; i++) {
        for (int j = W; j >= 0; j--) {
            if (j - wt[i] < W + 1 && j - wt[i] >= 0) {
                dp[j] = std::max(dp[j], val[i] + dp[j - wt[i]]);
            }
        }
    }
    return dp[W];
}
