void stoogesort(std::vector<int>& arr, int l, int h) {
    if (l >= h) {
        return;
    }
    if (arr[l] > arr[h]) {
        int t = arr[l];
        arr[l] = arr[h];
        arr[h] = t;
    }
    if (h - l + 1 > 2) {
        int t = (h - l + 1) / 3;
        stoogesort(arr, l, h - t);
        stoogesort(arr, l + t, h);
        stoogesort(arr, l, h - t);
    }
}

int main() {
    std::vector<int> arr = {5, 2, 8, 4, 1, 3, 9, 6, 7};
    int n = arr.size();

    stoogesort(arr, 0, n - 1);

    for (int i = 0; i < n; i++) {
        std::cout << arr[i] << " ";
    }

    return 0;
}
