int countUnique(std::vector<std::vector<int>> mat, int n, int m) {
    std::vector<int> rowsum(n, 0);
    std::vector<int> colsum(m, 0);
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (mat[i][j] != 0) {
                rowsum[i] += 1;
                colsum[j] += 1;
            }
        }
    }
    int uniquecount = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (mat[i][j] != 0 && rowsum[i] == 1 && colsum[j] == 1) {
                uniquecount += 1;
            }
        }
    }
    return uniquecount;
}
