int countTransformation(std::string a, std::string b) {
    int n = a.size();
    int m = b.size();
    if (m == 0) {
        return 1;
    }
    std::vector<std::vector<int>> dp(m + 1, std::vector<int>(n + 1, 0));
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < n; ++j) {
            if (i == 0) {
                if (j == 0) {
                    dp[i][j] = a[j] == b[i] ? 1 : 0;
                } else {
                    dp[i][j] = (a[j] == b[i]) ? dp[i][j - 1] + 1 : dp[i][j - 1];
                }
            } else {
                dp[i][j] = (a[j] == b[i]) ? (dp[i][j - 1] + dp[i - 1][j - 1]) : dp[i][j - 1];
            }
        }
    }
    return dp[m - 1][n - 1];
}

int main() {
    std::string a = "abcde";
    std::string b = "ace";
    std::cout << countTransformation(a, b) << std::endl; // Output: 1
    return 0;
