int nearestSmallerEqFib(int n) {
    if (n == 0 || n == 1) {
        return n;
    }
    int f1 = 0, f2 = 1, f3 = 1;
    while (f3 <= n) {
        f1 = f2;
        f2 = f3;
        f3 = f1 + f2;
    }
    return f2;
}

int main() {
    int n = 10;
    std::cout << nearestSmallerEqFib(n) << std::endl;
    return 0;
}
